<x-filament-panels::page><main class="pos"><header><div><span>FINANCE / PAYOUT GOVERNANCE</span><h1>Payout Provider Settings</h1><p>Settlement payout readiness and provider onboarding. No transfer or mark-paid action is enabled.</p></div><nav><a href="{{$financeUrl}}">Finance Control</a><a href="{{$securityUrl}}">System Security</a></nav></header><section class="kpis">@foreach([['Provider',$status['key']],['Environment',$status['environment']],['Outbound',$status['outbound_enabled']?'Enabled':'Blocked'],['Manual review',$status['manual_review_enabled']?'Configured':'Disabled'],['Approval',$status['approval_required']?'Required':'Not required'],['Provider ready',$status['configured']?'Yes':'No']] as [$l,$v])<article><span>{{$l}}</span><strong>{{$v}}</strong></article>@endforeach</section><section class="grid"><section class="panel"><span>PROVIDER CONFIGURATION</span><h2>Fail-closed settings</h2><label>Provider<select wire:model="providerKey"><option value="disabled">Disabled</option><option value="manual_bank_review">Manual bank review</option><option value="external_provider_deferred">External provider deferred</option></select></label><label>Environment<select wire:model="environment"><option value="local_review">Local review</option><option value="sandbox">Sandbox</option><option value="production">Production — blocked</option></select></label><label><input type="checkbox" wire:model="manualReviewEnabled"> Manual review enabled</label><label><input type="checkbox" wire:model="approvalRequired"> Approval required</label><label>Minimum amount<input type="number" step="0.01" wire:model="minimumAmount"></label><label>Notes<textarea wire:model="notes"></textarea></label><button wire:click="saveSettings">Save settings</button></section><section class="panel"><span>READINESS CHECKLIST</span><h2>{{($readiness['ready']??false)?'Ready':'Blocked'}}</h2>@forelse($readiness['blockers']??[] as $reason)<div class="row"><strong>Blocked</strong><em>{{$reason}}</em></div>@empty<div class="row"><strong>Ready</strong><em>All persisted gates passed.</em></div>@endforelse</section><aside class="panel blocked"><span>PROVIDER CONTRACT</span><h2>No real payout provider</h2><p>{{$status['reason']}}</p><button disabled title="{{$status['reason']}}">Prepare payout unavailable</button><button disabled title="Manual payout evidence workflow is not implemented.">Mark paid unavailable</button></aside></section></main><style>.pos{color:#eaf4ff;display:grid;gap:14px}.pos header,.panel,.kpis article{background:#071725;border:1px solid #20384b;border-radius:8px}.pos header{display:flex;justify-content:space-between;padding:20px}.pos span{color:var(--bkb-accent,#55e6b2);font-size:11px;font-weight:800}.pos h1{font-size:30px;margin:5px 0}.pos p{color:#94abc1}.pos nav{display:flex;gap:8px}.pos a,.pos button{background:#0b2937;border:1px solid #286078;border-radius:6px;color:#eaffff;padding:9px 12px;font-weight:700}.kpis{display:grid;grid-template-columns:repeat(6,1fr);gap:10px}.kpis article,.panel{padding:14px}.kpis strong{display:block;font-size:18px;margin-top:7px}.grid{display:grid;grid-template-columns:1fr 1fr .7fr;gap:12px}.row{display:grid;grid-template-columns:auto 1fr;gap:12px;padding:11px 0;border-bottom:1px solid #20384b}.row em{color:#9db2c7}.pos label{display:grid;gap:5px;margin-top:12px;color:#9db2c7}.pos input,.pos select,.pos textarea{background:#06131f;border:1px solid #29465b;color:#fff;padding:10px;border-radius:5px}.pos button{margin-top:10px}.blocked{border-color:#703942}@media(max-width:1100px){.kpis{grid-template-columns:repeat(3,1fr)}.grid{grid-template-columns:1fr 1fr}.blocked{grid-column:1/-1}}@media(max-width:700px){.pos header{display:block}.kpis,.grid{grid-template-columns:1fr 1fr}.grid .panel{grid-column:1/-1}}</style></x-filament-panels::page>
